import{c as e,Q as r,j as o,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Prompting Science Report 2: The Decreasing Value of Chain of Thought in Prompting","description":"","frontmatter":{"title":"Prompting Science Report 2: The Decreasing Value of Chain of Thought in Prompting","arxiv_id":2506.07142,"authors":"Lennart Meincke, Ethan Mollick, Lilach Mollick, Dan Shapiro","fetched":"2026-05-27T00:00:00.000Z","published":"2025-06-08T00:00:00.000Z","source":"https://arxiv.org/abs/2506.07142","source_tier":"P"},"headers":[],"relativePath":"research/papers/2025-06-08-decreasing-value-chain-of-thought-2506-07142.md","filePath":"research/papers/2025-06-08-decreasing-value-chain-of-thought-2506-07142.md","lastUpdated":1779901665000}'),d={name:"research/papers/2025-06-08-decreasing-value-chain-of-thought-2506-07142.md"};function a(n,t,s,l,h,c){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="prompting-science-report-2-the-decreasing-value-of-chain-of-thought-in-prompting" tabindex="-1">Prompting Science Report 2: The Decreasing Value of Chain of Thought in Prompting <a class="header-anchor" href="#prompting-science-report-2-the-decreasing-value-of-chain-of-thought-in-prompting" aria-label="Permalink to &quot;Prompting Science Report 2: The Decreasing Value of Chain of Thought in Prompting&quot;">​</a></h1><p><strong>Authors</strong>: Lennart Meincke¹², Ethan Mollick¹, Lilach Mollick¹, Dan Shapiro¹³ <strong>Affiliations</strong>:</p><ol><li>Generative AI Labs, The Wharton School of Business, University of Pennsylvania</li><li>WHU–Otto Beisheim School of Management</li><li>Glowforge</li></ol><p><strong>Published</strong>: June 8, 2025 <strong>Source</strong>: <a href="https://arxiv.org/abs/2506.07142" target="_blank" rel="noreferrer">https://arxiv.org/abs/2506.07142</a><strong>arXiv ID</strong>: 2506.07142 <strong>Categories</strong>: cs.CL / cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>This is the second in a series of short reports that seek to help business, education, and policy leaders understand the technical details of working with AI through rigorous testing. In this report, we investigate Chain-of-Thought (CoT) prompting, a technique that encourages a large language model (LLM) to &quot;think step by step&quot; (Wei et al., 2022). CoT is a widely adopted method for improving reasoning tasks, however, our findings reveal a more nuanced picture of its effectiveness. We demonstrate two things:</p><ul><li>The effectiveness of Chain-of-Thought prompting can vary greatly depending on the type of task and model. For non-reasoning models, CoT generally improves average performance by a small amount, particularly if the model does not inherently engage in step-by-step processing by default. However, CoT can introduce more variability in answers, sometimes triggering occasional errors in questions the model would otherwise get right. We also found that many recent models perform some form of CoT reasoning even if not asked; for these models, a request to perform CoT had little impact. Performing CoT generally requires far more tokens (increasing cost and time) than direct answers.</li><li>For models designed with explicit reasoning capabilities, CoT prompting often results in only marginal, if any, gains in answer accuracy. However, it significantly increases the time and tokens needed to generate a response.</li></ul><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>CoT prompting&#39;s utility has diminished as models have evolved: non-reasoning models already perform implicit CoT by default, making explicit CoT prompts redundant for recent models, while reasoning models see only marginal accuracy gains (RD ≤ 0.031) at a 20–80% time cost increase. The traditional CoT benefit applies mainly to older or smaller non-reasoning models that do not engage in step-by-step processing by default.</p><hr><h2 id="benchmark-and-methodology" tabindex="-1">Benchmark and Methodology <a class="header-anchor" href="#benchmark-and-methodology" aria-label="Permalink to &quot;Benchmark and Methodology&quot;">​</a></h2><h3 id="dataset" tabindex="-1">Dataset <a class="header-anchor" href="#dataset" aria-label="Permalink to &quot;Dataset&quot;">​</a></h3><p><strong>GPQA Diamond</strong> (Graduate-Level Google-Proof Q&amp;A Benchmark, Rein et al. 2024): 198 multiple-choice PhD-level questions across biology, physics, and chemistry.</p><ul><li>PhD accuracy in corresponding domain: 65% (74% discounting identified mistakes)</li><li>Highly skilled non-expert validators: 34% accuracy (with &gt;30 min unrestricted web access)</li></ul><h3 id="models-tested" tabindex="-1">Models Tested <a class="header-anchor" href="#models-tested" aria-label="Permalink to &quot;Models Tested&quot;">​</a></h3><p><strong>Non-Reasoning Models:</strong></p><ul><li>Sonnet 3.5 (claude-3-5-sonnet-20240620)</li><li>Gemini 2.0 Flash (gemini-2.0-flash-001)</li><li>GPT-4o-mini (gpt-4o-mini-2024-07-18)</li><li>GPT-4o (gpt-4o-2024-08-06)</li><li>Gemini Pro 1.5 (gemini-1.5-pro-001)</li></ul><p><strong>Reasoning Models:</strong></p><ul><li>o3-mini (o3-mini-2025-01-31)</li><li>o4-mini (o4-mini-2025-04-16)</li><li>Gemini Flash 2.5 (gemini-2.5-flash-preview-05-20)</li></ul><h3 id="experimental-design" tabindex="-1">Experimental Design <a class="header-anchor" href="#experimental-design" aria-label="Permalink to &quot;Experimental Design&quot;">​</a></h3><ul><li>25 trials per question per condition (4,950 runs per prompt per model)</li><li>Temperature = 0</li><li>Correlation between 25-trial and 100-trial results is very high (see Table S2)</li></ul><h3 id="performance-metrics" tabindex="-1">Performance Metrics <a class="header-anchor" href="#performance-metrics" aria-label="Permalink to &quot;Performance Metrics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td><strong>100% Correct</strong></td><td>Must get all 25/25 trials correct — strictest, zero-error tolerance</td></tr><tr><td><strong>90% Correct</strong></td><td>At least 23/25 trials correct — comparable to human acceptable error rates</td></tr><tr><td><strong>51% Correct</strong></td><td>Simple majority: at least 13/25 trials correct</td></tr><tr><td><strong>Average Rating</strong></td><td>Overall mean across all trials and all questions (N = 4,950)</td></tr></tbody></table><p><em>Note: PASS@N and CONSENSUS metrics excluded as not useful for real-world benchmarking.</em></p><h3 id="prompt-conditions" tabindex="-1">Prompt Conditions <a class="header-anchor" href="#prompt-conditions" aria-label="Permalink to &quot;Prompt Conditions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Prompt</th></tr></thead><tbody><tr><td><strong>Direct</strong></td><td>&quot;Answer directly without any explanation or thinking. Just provide the answer.&quot;</td></tr><tr><td><strong>Step by step</strong></td><td>&quot;Think step by step&quot; appended to question</td></tr><tr><td><strong>Default</strong></td><td>No suffix, no formatting constraint — model chooses reply format</td></tr></tbody></table><p>Different CoT prompt variants (Step by Step, Think Carefully, Decompose Problem, Weigh Paths) showed negligible differences (Figure S3).</p><hr><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><h3 id="non-reasoning-models-direct-vs-cot-step-by-step" tabindex="-1">Non-Reasoning Models: Direct vs. CoT (Step by Step) <a class="header-anchor" href="#non-reasoning-models-direct-vs-cot-step-by-step" aria-label="Permalink to &quot;Non-Reasoning Models: Direct vs. CoT (Step by Step)&quot;">​</a></h3><p>CoT generally improved <strong>Average</strong> performance but had mixed effects on <strong>100% Correct</strong> metric:</p><table tabindex="0"><thead><tr><th>Model</th><th>Average RD</th><th>p</th><th>100% Correct RD</th><th>p</th></tr></thead><tbody><tr><td>Sonnet 3.5</td><td>+0.117</td><td>&lt;0.001</td><td>+0.101</td><td>0.001</td></tr><tr><td>Gemini 2.0 Flash</td><td>+0.135</td><td>&lt;0.001</td><td><strong>−0.131</strong></td><td>&lt;0.001</td></tr><tr><td>GPT-4o-mini</td><td>+0.044</td><td>0.067 (ns)</td><td><strong>−0.091</strong></td><td>0.001</td></tr><tr><td>GPT-4o</td><td>+0.072</td><td>0.003</td><td>+0.010</td><td>0.624 (ns)</td></tr><tr><td>Gemini Pro 1.5</td><td>+0.071</td><td>0.014</td><td><strong>−0.172</strong></td><td>&lt;0.001</td></tr></tbody></table><p>Key finding: In 3 of 5 non-reasoning models, CoT <strong>harmed</strong> perfect-accuracy performance while raising average performance — models introduced new errors on questions they previously got consistently right.</p><p>CoT latency overhead for non-reasoning models: <strong>35–600% longer</strong> (5–15 seconds per question).</p><h3 id="non-reasoning-models-default-vs-cot" tabindex="-1">Non-Reasoning Models: Default vs. CoT <a class="header-anchor" href="#non-reasoning-models-default-vs-cot" aria-label="Permalink to &quot;Non-Reasoning Models: Default vs. CoT&quot;">​</a></h3><p>Gains from CoT relative to the <strong>default</strong> (unprompted) behavior were much smaller:</p><table tabindex="0"><thead><tr><th>Model</th><th>Average RD</th><th>p</th></tr></thead><tbody><tr><td>Sonnet 3.5</td><td>−0.019</td><td>0.189 (ns)</td></tr><tr><td>Gemini 2.0 Flash</td><td>+0.062</td><td>&lt;0.001</td></tr><tr><td>GPT-4o-mini</td><td>+0.004</td><td>0.728 (ns)</td></tr><tr><td>GPT-4o</td><td>+0.069</td><td>0.003</td></tr></tbody></table><p>Reason: Many non-reasoning models already perform CoT implicitly when unprompted. Explicit CoT instruction adds little value.</p><p>Additional finding: Prompting a model to answer <em>only</em> (no reasoning tokens) likely harms non-reasoning model performance by suppressing implicit CoT.</p><h3 id="reasoning-models-direct-vs-cot" tabindex="-1">Reasoning Models: Direct vs. CoT <a class="header-anchor" href="#reasoning-models-direct-vs-cot" aria-label="Permalink to &quot;Reasoning Models: Direct vs. CoT&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Average RD</th><th>p</th><th>100% Correct RD</th><th>p</th></tr></thead><tbody><tr><td>o3-mini</td><td>+0.029</td><td>0.024</td><td>+0.015</td><td>0.738 (ns)</td></tr><tr><td>o4-mini</td><td>+0.031</td><td>0.003</td><td>+0.010</td><td>0.731 (ns)</td></tr><tr><td>Gemini Flash 2.5</td><td><strong>−0.033</strong></td><td>0.005</td><td><strong>−0.131</strong></td><td>0.001</td></tr></tbody></table><p>CoT on reasoning models: marginal or negative accuracy impact, with <strong>20–80% longer</strong> response time (10–20 seconds per question).</p><hr><h2 id="discussion-and-conclusion" tabindex="-1">Discussion and Conclusion <a class="header-anchor" href="#discussion-and-conclusion" aria-label="Permalink to &quot;Discussion and Conclusion&quot;">​</a></h2><p><strong>Non-reasoning models:</strong></p><ul><li>CoT is still a useful tool for boosting <em>average</em> performance, especially for older/smaller models without implicit step-by-step processing</li><li>CoT introduces higher variability — can harm &quot;easy&quot; question accuracy while improving &quot;hard&quot; question accuracy</li><li>Many recent non-reasoning models already perform implicit CoT, making explicit prompting redundant</li><li>CoT increases token count, time, and cost</li></ul><p><strong>Reasoning models:</strong></p><ul><li>Benefits of explicit CoT on answer accuracy are marginal at best</li><li>Given substantial increases in response time and tokens, CoT utility for reasoning models is questionable for most practical purposes</li></ul><p><strong>Decision framework:</strong> CoT prompting decisions should be guided by:</p><ol><li>The specific model&#39;s characteristics</li><li>Task requirements</li><li>Balance between accuracy improvement, tolerance for variability, and acceptable response latency</li></ol><h3 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h3><ul><li>Limited set of models tested</li><li>Single benchmark (GPQA Diamond)</li><li>Simple CoT variant used (though sophisticated variants showed negligible differences in Figure S3)</li><li>Highly customized, task-specific CoT may yield larger benefits than generic approaches</li></ul><hr><h2 id="supplementary-data" tabindex="-1">Supplementary Data <a class="header-anchor" href="#supplementary-data" aria-label="Permalink to &quot;Supplementary Data&quot;">​</a></h2><h3 id="table-s2-25-vs-100-trials-comparison-gpt-4o-mini-direct-condition" tabindex="-1">Table S2: 25 vs. 100 Trials Comparison (GPT-4o-mini, Direct Condition) <a class="header-anchor" href="#table-s2-25-vs-100-trials-comparison-gpt-4o-mini-direct-condition" aria-label="Permalink to &quot;Table S2: 25 vs. 100 Trials Comparison (GPT-4o-mini, Direct Condition)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>N Trials</th><th>Metric</th><th>Estimate [95% CI]</th></tr></thead><tbody><tr><td>25</td><td>Average</td><td>0.389 [0.382, 0.396]</td></tr><tr><td>100</td><td>Average</td><td>0.389 [0.385, 0.393]</td></tr><tr><td>25</td><td>100%</td><td>0.185 [0.162, 0.207]</td></tr><tr><td>100</td><td>100%</td><td>0.147 [0.136, 0.162]</td></tr><tr><td>25</td><td>51%</td><td>0.380 [0.364, 0.394]</td></tr><tr><td>100</td><td>51%</td><td>0.377 [0.369, 0.389]</td></tr><tr><td>25</td><td>90%</td><td>0.247 [0.227, 0.263]</td></tr><tr><td>100</td><td>90%</td><td>0.249 [0.237, 0.263]</td></tr></tbody></table><p><em>No metric reached statistical significance at α=0.05; 25 trials provide comparable precision to 100 trials.</em></p><h3 id="table-s3-full-pairwise-comparisons-—-non-reasoning-models-direct-vs-cot" tabindex="-1">Table S3: Full Pairwise Comparisons — Non-Reasoning Models (Direct vs. CoT) <a class="header-anchor" href="#table-s3-full-pairwise-comparisons-—-non-reasoning-models-direct-vs-cot" aria-label="Permalink to &quot;Table S3: Full Pairwise Comparisons — Non-Reasoning Models (Direct vs. CoT)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Metric</th><th>RD [95% CI]</th><th>p</th></tr></thead><tbody><tr><td>Sonnet 3.5</td><td>Average</td><td>0.117 [0.069, 0.166]</td><td>&lt;0.001</td></tr><tr><td>Sonnet 3.5</td><td>100%</td><td>0.101 [0.040, 0.162]</td><td>0.001</td></tr><tr><td>Sonnet 3.5</td><td>90%</td><td>0.136 [0.071, 0.202]</td><td>&lt;0.001</td></tr><tr><td>Sonnet 3.5</td><td>51%</td><td>0.131 [0.056, 0.207]</td><td>0.001</td></tr><tr><td>Gemini 2.0 Flash</td><td>Average</td><td>0.135 [0.076, 0.199]</td><td>&lt;0.001</td></tr><tr><td>Gemini 2.0 Flash</td><td>100%</td><td>−0.131 [−0.207, −0.056]</td><td>&lt;0.001</td></tr><tr><td>Gemini 2.0 Flash</td><td>90%</td><td>−0.030 [−0.101, 0.045]</td><td>0.381 (ns)</td></tr><tr><td>Gemini 2.0 Flash</td><td>51%</td><td>0.136 [0.061, 0.212]</td><td>&lt;0.001</td></tr><tr><td>GPT-4o-mini</td><td>Average</td><td>0.044 [−0.003, 0.090]</td><td>0.067 (ns)</td></tr><tr><td>GPT-4o-mini</td><td>100%</td><td>−0.091 [−0.141, −0.035]</td><td>0.001</td></tr><tr><td>GPT-4o-mini</td><td>90%</td><td>−0.066 [−0.126, −0.010]</td><td>0.033</td></tr><tr><td>GPT-4o-mini</td><td>51%</td><td>0.020 [−0.045, 0.086]</td><td>0.609 (ns)</td></tr><tr><td>GPT-4o</td><td>Average</td><td>0.072 [0.028, 0.118]</td><td>0.003</td></tr><tr><td>GPT-4o</td><td>100%</td><td>0.010 [−0.040, 0.061]</td><td>0.624 (ns)</td></tr><tr><td>GPT-4o</td><td>90%</td><td>0.035 [−0.015, 0.086]</td><td>0.150 (ns)</td></tr><tr><td>GPT-4o</td><td>51%</td><td>0.071 [0.000, 0.141]</td><td>0.042</td></tr><tr><td>Gemini Pro 1.5</td><td>Average</td><td>0.071 [0.018, 0.128]</td><td>0.014</td></tr><tr><td>Gemini Pro 1.5</td><td>100%</td><td>−0.172 [−0.242, −0.101]</td><td>&lt;0.001</td></tr><tr><td>Gemini Pro 1.5</td><td>90%</td><td>−0.131 [−0.197, −0.066]</td><td>&lt;0.001</td></tr><tr><td>Gemini Pro 1.5</td><td>51%</td><td>0.056 [−0.015, 0.126]</td><td>0.097 (ns)</td></tr></tbody></table><h3 id="table-s4-full-pairwise-comparisons-—-non-reasoning-models-default-vs-cot" tabindex="-1">Table S4: Full Pairwise Comparisons — Non-Reasoning Models (Default vs. CoT) <a class="header-anchor" href="#table-s4-full-pairwise-comparisons-—-non-reasoning-models-default-vs-cot" aria-label="Permalink to &quot;Table S4: Full Pairwise Comparisons — Non-Reasoning Models (Default vs. CoT)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Metric</th><th>RD [95% CI]</th><th>p</th></tr></thead><tbody><tr><td>Sonnet 3.5</td><td>Average</td><td>−0.019 [−0.047, 0.009]</td><td>0.189 (ns)</td></tr><tr><td>Gemini 2.0 Flash</td><td>Average</td><td>0.062 [0.028, 0.095]</td><td>&lt;0.001</td></tr><tr><td>Gemini 2.0 Flash</td><td>100%</td><td>0.071 [0.005, 0.136]</td><td>0.039</td></tr><tr><td>Gemini 2.0 Flash</td><td>90%</td><td>0.111 [0.045, 0.177]</td><td>&lt;0.001</td></tr><tr><td>GPT-4o-mini</td><td>Average</td><td>0.004 [−0.021, 0.031]</td><td>0.728 (ns)</td></tr><tr><td>GPT-4o</td><td>Average</td><td>0.069 [0.023, 0.113]</td><td>0.003</td></tr></tbody></table><h3 id="table-s5-full-pairwise-comparisons-—-reasoning-models-direct-vs-cot" tabindex="-1">Table S5: Full Pairwise Comparisons — Reasoning Models (Direct vs. CoT) <a class="header-anchor" href="#table-s5-full-pairwise-comparisons-—-reasoning-models-direct-vs-cot" aria-label="Permalink to &quot;Table S5: Full Pairwise Comparisons — Reasoning Models (Direct vs. CoT)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Metric</th><th>RD [95% CI]</th><th>p</th></tr></thead><tbody><tr><td>o3-mini</td><td>Average</td><td>0.029 [0.003, 0.053]</td><td>0.024</td></tr><tr><td>o3-mini</td><td>100%</td><td>0.015 [−0.056, 0.086]</td><td>0.738 (ns)</td></tr><tr><td>o3-mini</td><td>90%</td><td>0.030 [−0.025, 0.086]</td><td>0.332 (ns)</td></tr><tr><td>o3-mini</td><td>51%</td><td>0.000 [−0.040, 0.040]</td><td>1.000 (ns)</td></tr><tr><td>o4-mini</td><td>Average</td><td>0.031 [0.010, 0.052]</td><td>0.003</td></tr><tr><td>o4-mini</td><td>100%</td><td>0.010 [−0.061, 0.081]</td><td>0.731 (ns)</td></tr><tr><td>o4-mini</td><td>90%</td><td>0.051 [−0.005, 0.106]</td><td>0.106 (ns)</td></tr><tr><td>o4-mini</td><td>51%</td><td>0.056 [0.015, 0.096]</td><td>0.003</td></tr><tr><td>Gemini Flash 2.5</td><td>Average</td><td>−0.033 [−0.056, −0.010]</td><td>0.005</td></tr><tr><td>Gemini Flash 2.5</td><td>100%</td><td>−0.131 [−0.207, −0.056]</td><td>0.001</td></tr><tr><td>Gemini Flash 2.5</td><td>90%</td><td>−0.071 [−0.131, −0.010]</td><td>0.016</td></tr><tr><td>Gemini Flash 2.5</td><td>51%</td><td>−0.035 [−0.076, 0.005]</td><td>0.060 (ns)</td></tr></tbody></table><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ul><li><strong>Wei et al. (2022)</strong> — Chain-of-thought prompting elicits reasoning in large language models. <em>NeurIPS 2022</em>, 24824–24837.</li><li><strong>Rein et al. (2024)</strong> — GPQA: A Graduate-Level Google-Proof Q&amp;A Benchmark. <em>First Conference on Language Modeling.</em></li><li><strong>Miller (2024)</strong> — Adding Error Bars to Evals: A Statistical Approach to Language Model Evaluations. arXiv:2411.00640.</li><li><strong>Meincke et al. (2025)</strong> — Prompting Science Report 1: Prompt Engineering is Complicated and Contingent. SSRN:5165270.</li></ul>',68)])])}const p=e(d,[["render",a]]);export{g as __pageData,p as default};
